import{_ as r,c as t,o as _,a}from"./app.015fbf38.js";const f='{"title":"\u4F46\u4EE5\u7406\u66F8\u524D\u8A00","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u524D\u8A00","date":"2018-05-08T09:51:01.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180507_\u4F46\u4EE5\u7406\u66F8\u524D\u8A00.md","lastUpdated":1648513476165}',e={},p=a('<p><img src="https://farm1.staticflickr.com/963/28114690008_3efba4b440.jpg" alt=""><br></p><p>\u9019\u4E00\u5E74\u4F86\uFF0C\u9A0E\u55AE\u8ECA\u9A0E\u5F97\u592A\u5147\u4E86\uFF0C\u60F3\u5230\u8056\u7D93\u7684\u8A71\uFF0C\u656C\u8654\u51E1\u662F\u90FD\u6709\u76CA\u8655<br> \u60F3\u91CD\u62FE\u4EE5\u524D\u67E5\u7D93\u7684\u6A02\u8DA3\uFF0C\u56E0\u6B64\u5F80\u5F8C\u6BCF\u9031\u6703\u82B1\u9EDE\u6642\u9593\u4F86\u5206\u6790\u3001\u8B80\u7D93<br> \u7B2C\u4E00\u500B\u6311\u9078\u7684\u66F8\u5377\u662F\u4F46\u4EE5\u7406\u66F8\uFF0C\u56E0\u70BA\u4F46\u4EE5\u7406\u662F\u751F\u6D3B\u5728\u5916\u90A6\u7684\u7336\u592A\u4EBA<br> \u4F46\u4EE5\u7406\u6C92\u6709\u5C48\u670D\u5728\u7576\u4EE3\u4E16\u754C\u6F6E\u6D41\uFF0C\u4E5F\u4E0D\u88AB\u7576\u6642\u738B\u6B0A\u3001\u7570\u6559\u6587\u5316\u6240\u5F71\u97FF<br> \u53CD\u800C\uFF0C\u56E0\u8457\u656C\u8654\u3001\u901A\u9054\u9010\u6A23\u7684\u5B78\u554F\uFF0C\u670D\u4E8B\u4E09\u4EE3\u541B\u738B\uFF0C\u6975\u5177\u5F71\u97FF\u529B\u7684\u57FA\u7763\u5F92<br> \u4E5F\u900F\u904E\u4F46\u4EE5\u7406\u751F\u547D\u7F8E\u597D\u7684\u898B\u8B49\uFF0C\u5B78\u7FD2\u5728\u4E0D\u540C\u738B\u4E4B\u9593\u5982\u4F55\u6D3B\u51FA\u656C\u8654\u7684\u751F\u6D3B</p><p><img src="https://farm1.staticflickr.com/831/41245310004_2da1600245.jpg" alt=""></p><p>\u5F9E\u4F46\u4EE5\u7406\u66F8\u7576\u4E2D\u53EF\u4EE5\u770B\u898B\uFF0C\u4E3B\u8981\u4E09\u9EDE</p><ol><li><p>\u795E\u7684\u5D07\u9AD8\u6027<br> \u4E16\u4E0A\u7684\u541B\u738B\u5728\u4F4D\u6642\uFF0C\u7121\u8AD6\u5176\u671D\u4EE3\u5982\u4F55\u9577\u5EF6<br> \u738B\u6B0A\u5982\u4F55\u64F4\u5F35\uFF0C\u7D42\u5C07\u96E3\u9003\u50BE\u8986\u66F4\u8FED\u7684\u547D\u904B<br> \u6027\u60C5\u591A\u8B8A\u7684\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\uFF0C\u66F4\u662F\u6B98\u66B4\u7684\u541B\u4E3B<br> \u9806\u8457\u672C\u5377\u66F8\u5287\u60C5\u767C\u5C55\uFF0C\u795E\u6700\u7D42\u662F\u8D85\u8D8A\u4E00\u5207\u6B0A\u67C4\u7684\u541B\u738B</p></li><li><p>\u795E\u7684\u4E3B\u5BB0\u6027<br> \u897F\u5143\u524D586\u5E74\uFF0C\u8036\u8DEF\u6492\u51B7\u6DEA\u9677\uFF0C\u5357\u570B\u7336\u5927\u570B\u6EC5\u4EA1\u3002\u4EE5\u8272\u5217\u4EBA\u6DEA\u70BA\u201C\u5DF4\u6BD4\u502B\u4E4B\u56DA\u201D<br> \u4F46\u5728\u6D41\u653E\u7684\u904E\u7A0B\u4E2D\uFF0C\u4ED6\u5011\u7684\u751F\u6D3B\u7FD2\u6163\u3001\u6C11\u65CF\u610F\u8B58\u548C\u5B97\u6559\u611F\u60C5\u8207\u7576\u5730\u4EBA\u8FE5\u7136\u6709\u5225<br> \u96D6\u7136\u770B\u662F\u570B\u5BB6\u6EC5\u4EA1\uFF0C\u4F46\u5176\u5BE6\u795E\u4FDD\u5B88\u4EE5\u8272\u5217\u4EBA\u5728\u88AB\u64C4\u4E4B\u5730\u7684\u751F\u6D3B<br> \u9019\u4E00\u5207\u4E5F\u90FD\u662F\u5728\u795E\u7684\u5B89\u6392\u8A08\u756B\u4E4B\u4E2D\uFF0C\u4EE5\u8272\u5217\u6C11\u65CF\u6700\u5F8C\u6709\u56DE\u6B78\u7684\u6B77\u53F2</p></li><li><p>\u795E\u7684\u9810\u77E5\u6027<br> \u672C\u5377\u66F8\u662F\u5C6C\u65BC\u8056\u7D93\u4E2D\u7684\u555F\u793A\u6587\u5B78\uFF0C\u5F9E\u4E2D\u770B\u51FA\u795E\u7684\u9810\u77E5\u6027<br> \u795E\u900F\u904E\u4F46\u4EE5\u7406\u5BEB\u51FA\u672A\u4F86\u5C07\u5D1B\u8D77\u7684\u5F37\u570B\uFF0C\u6975\u5176\u843D\u5BDE\u72C0\u6CC1<br> \u4F46\u4EE5\u7406\u7559\u610F\u5148\u77E5\u8036\u5229\u7C73\u9810\u8A00\u8036\u8DEF\u6492\u51B7\u8352\u6DBC\u7684\u65E5\u671F\u662F\u4E03\u5341\u5E74<br> \u800C\u4F46\u4EE5\u7406\u7981\u98DF\u79B1\u544A\u5F8C\uFF0C\u795E\u4E5F\u7167\u6240\u9810\u5B9A\u7684\u65E5\u671F\u5BE6\u73FE\u61C9\u8A31</p></li></ol><p>\u53E6\u5916\u6BD4\u5C0D\u4F46\u4EE5\u7406\u8207\u7D04\u745F\u7684\u6642\u5019\uFF0C\u6703\u767C\u73FE\u5169\u8005\u6709\u8A31\u591A\u76F8\u540C\u8655<br> -\u5E74\u8F15\u6642\u88AB\u64C4\uFF0F\u88AB\u8CE3<br> -\u70BA\u738B\u89E3\u5922<br> -\u5728\u5916\u90A6\u5C45\u9AD8\u4F4D<br> -\u795E\u70BA\u4EE5\u8272\u5217\u5B58\u7559\u9918\u7A2E\uFF0C\u53C8\u5927\u65BD\u62EF\u6551<br> -\u4E00\u751F\u656C\u8654\u611B\u4E3B</p><p>\u4F46\u4EE5\u7406\u66F8\u5F9E\u7B2C\u4E8C\u7AE0\u5230\u7B2C\u4E03\u7AE0\u7686\u662F\u4F7F\u7528\u4E9E\u862D\u6587<br> \u5176\u4ED6\u90E8\u5206\u70BA\u4F7F\u7528\u5E0C\u4F2F\u4F86\u6587\u64B0\u5BEB\uFF0C\u53E6\u5916\u4F5C\u8005\u90E8\u5206\u4E5F\u6709\u722D\u8B70<br> \u5F8C\u534A\u90E8\u7684\u555F\u793A\u5167\u5BB9\uFF0C\u6703\u8B93\u4EBA\u4EE5\u70BA\u662F\u5F8C\u4EBA\u6240\u5BEB\u7684<br> \u6709\u5B78\u8005\u8A8D\u70BA\u662F\u897F\u5143\u524D\u4E8C\u4E16\u7D00\u88DC\u4E0A\u53BB\u7684\uFF0C\u56E0\u70BA\u5F88\u591A\u90FD\u6709\u5BE6\u73FE<br> \u4E0D\u904E\u8056\u7D93\u5404\u5377\u66F8\u4F5C\u8005\u672C\u4F86\u5C31\u4E0D\u6613\u754C\u5B9A\uFF0C\u5C31\u4E0D\u591A\u6DF1\u5165\u63A2\u8A0E</p><p>\u5F9E\u4F46\u4EE5\u7406\u66F8\u53EF\u4EE5\u770B\u5230\u4EBA\u5C0D\u795E\u7684\u4FE1\u5FC3\uFF0C\u9032\u800C\u5E36\u51FA\u795E\u5C0D\u4EBA\u7684\u5B89\u6392<br> \u800C\u7336\u5927\u4EBA\u7684\u4E0D\u9806\u670D\u9020\u6210\u4EA1\u570B\uFF0C\u4E5F\u5C0D\u6BD4\u4F46\u4EE5\u7406\u5C0D\u795E\u7684\u9806\u670D\u5E36\u4E0B\u795E\u8E5F<br><img src="https://farm1.staticflickr.com/979/41064913035_87561b866d.jpg" alt=""></p>',8),b=[p];function c(i,s,o,l,d,n){return _(),t("div",null,b)}var g=r(e,[["render",c]]);export{f as __pageData,g as default};
